import { useState } from "react"
import { Link, useLocation, useNavigate } from "react-router"
import { loginSchema } from "@/features/auth/auth-schema"
import { login } from "@/features/auth/auth-api"
import { useAuthStore } from "@/features/auth/auth-store"

const returnPath = (value: unknown) =>
  typeof value === "string" && value.startsWith("/") && !value.startsWith("//")
    ? value
    : "/dashboard"
export function Component() {
  const navigate = useNavigate()
  const location = useLocation()
  const setSession = useAuthStore((state) => state.setSession)
  const [error, setError] = useState("")
  const [pending, setPending] = useState(false)
  const submit = async (form: FormData) => {
    const parsed = loginSchema.safeParse(Object.fromEntries(form))
    if (!parsed.success)
      return setError(parsed.error.issues[0]?.message ?? "Check your details.")
    setPending(true)
    setError("")
    try {
      setSession(await login(parsed.data))
      navigate(returnPath(location.state?.from), { replace: true })
    } catch {
      setError("Email or password is incorrect.")
    } finally {
      setPending(false)
    }
  }
  return (
    <main className="grid min-h-svh place-items-center p-6">
      <form
        action={submit}
        className="w-full max-w-sm space-y-4 rounded-xl border bg-card p-6 shadow-sm"
      >
        <div>
          <h1 className="text-2xl font-semibold">Sign in</h1>
          <p className="text-sm text-muted-foreground">
            Access your inventory workspace.
          </p>
        </div>
        <label className="block text-sm">
          Email
          <input
            className="mt-1 w-full rounded-md border bg-background p-2"
            name="email"
            type="email"
            autoComplete="email"
          />
        </label>
        <label className="block text-sm">
          Password
          <input
            className="mt-1 w-full rounded-md border bg-background p-2"
            name="password"
            type="password"
            autoComplete="current-password"
          />
        </label>
        {error && <p className="text-sm text-destructive">{error}</p>}
        <button
          className="w-full rounded-md bg-primary p-2 text-primary-foreground disabled:opacity-50"
          disabled={pending}
        >
          {pending ? "Signing in…" : "Sign in"}
        </button>
        <p className="text-sm text-muted-foreground">
          New here?{" "}
          <Link className="text-primary underline" to="/register">
            Create an account
          </Link>
        </p>
      </form>
    </main>
  )
}

