            }
        }
    }

    /// <inheritdoc />
    protected override void Dispose(bool disposing)
    {
        if (disposing)
        {
            Environment.SetEnvironmentVariable(
                ConnectionStringEnvironmentVariable,
                _originalConnectionString);
        }

        base.Dispose(disposing);
    }
}

