 10	/// <summary>Issues short-lived signed access tokens.</summary>
 11	public sealed class JwtAccessTokenIssuer(IOptions<JwtOptions> options, TimeProvider timeProvider)
 12	{
 13	    private readonly JwtOptions _options = options.Value;
 14	    /// <summary>Creates an access token for a user.</summary>
 15	    public (string Token, DateTimeOffset ExpiresAtUtc) Issue(AuthenticatedUser user)
 16	    {
 17	        var expiresAtUtc = timeProvider.GetUtcNow().AddMinutes(_options.AccessTokenLifetimeMinutes);
 18	        var credentials = new SigningCredentials(new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_options.SigningKey)), SecurityAlgorithms.HmacSha256);
 19	        var claims = new[] { new Claim(JwtRegisteredClaimNames.Sub, user.Id.ToString()), new Claim(ClaimTypes.NameIdentifier, user.Id.ToString()), new Claim(ClaimTypes.Email, user.Email), new Claim("display_name", user.DisplayName) };
 20	        var token = new JwtSecurityToken(_options.Issuer, _options.Audience, claims, notBefore: timeProvider.GetUtcNow().UtcDateTime, expires: expiresAtUtc.UtcDateTime, signingCredentials: credentials);
 21	        return (new JwtSecurityTokenHandler().WriteToken(token), expiresAtUtc);
 22	    }
 23	}
