    13	  headers: { "Content-Type": "application/json" },
    14	})
    15	
    16	let refreshPromise: Promise<string | null> | null = null
    17	const refreshAccessToken = () => {
    18	  if (!refreshPromise) {
    19	    refreshPromise = authClient
    20	      .post("/api/auth/refresh")
    21	      .then((response) => {
    22	        useAuthStore.getState().setSession(response.data)
    23	        return response.data.accessToken as string
    24	      })
    25	      .catch(() => {
    26	        useAuthStore.getState().clearSession()
    27	        return null
    28	      })
    29	      .finally(() => {
    30	        refreshPromise = null
    31	      })
    32	  }
    33	  return refreshPromise
    34	}
    35	
    36	apiClient.interceptors.request.use((config) => {
    37	  const token = useAuthStore.getState().accessToken
    38	  if (token) config.headers.Authorization = `Bearer ${token}`
    39	  return config
    40	})
    41	apiClient.interceptors.response.use(undefined, async (error: AxiosError) => {
    42	  const request = error.config as
    43	    (InternalAxiosRequestConfig & { _authRetried?: boolean }) | undefined
    44	  if (error.response?.status !== 401 || !request || request._authRetried)
    45	    return Promise.reject(error)
    46	  request._authRetried = true
    47	  const token = await refreshAccessToken()
    48	  if (!token) return Promise.reject(error)
    49	  request.headers.Authorization = `Bearer ${token}`
    50	  return apiClient(request)
    51	})
